-- DukaPOS Kenyan-ready sample dataset (PostgreSQL)
-- Generated for demo/testing purposes. Review tax mapping with your accountant/KRA before production use.

BEGIN;

DROP VIEW IF EXISTS vw_low_stock_products;
DROP TABLE IF EXISTS stock_movements CASCADE;
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS suppliers CASCADE;
DROP TABLE IF EXISTS categories CASCADE;
DROP TABLE IF EXISTS tax_codes CASCADE;

CREATE TABLE tax_codes (
    id SERIAL PRIMARY KEY,
    code VARCHAR(20) NOT NULL UNIQUE,
    name VARCHAR(100) NOT NULL,
    tax_type VARCHAR(20) NOT NULL CHECK (tax_type IN ('standard','zero_rated','exempt')),
    rate NUMERIC(5,2) NOT NULL DEFAULT 0.00
);

CREATE TABLE categories (
    id SERIAL PRIMARY KEY,
    name VARCHAR(100) NOT NULL UNIQUE,
    default_tax_type VARCHAR(20) NOT NULL CHECK (default_tax_type IN ('standard','zero_rated','exempt'))
);

CREATE TABLE suppliers (
    id SERIAL PRIMARY KEY,
    name VARCHAR(150) NOT NULL,
    contact_phone VARCHAR(30),
    address TEXT,
    is_active BOOLEAN NOT NULL DEFAULT TRUE
);

CREATE TABLE products (
    id SERIAL PRIMARY KEY,
    name VARCHAR(150) NOT NULL,
    sku VARCHAR(30) NOT NULL UNIQUE,
    barcode VARCHAR(20) UNIQUE,
    category_id INT NOT NULL REFERENCES categories(id),
    supplier_id INT REFERENCES suppliers(id),
    unit_of_measure VARCHAR(20) NOT NULL DEFAULT 'pcs',
    pack_size VARCHAR(50),
    cost_price NUMERIC(12,2) NOT NULL DEFAULT 0.00,
    selling_price NUMERIC(12,2) NOT NULL DEFAULT 0.00,
    tax_id INT NOT NULL REFERENCES tax_codes(id),
    reorder_level INT NOT NULL DEFAULT 0,
    current_stock INT NOT NULL DEFAULT 0,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW()
);

CREATE TABLE stock_movements (
    id BIGSERIAL PRIMARY KEY,
    product_id INT NOT NULL REFERENCES products(id) ON DELETE CASCADE,
    movement_type VARCHAR(30) NOT NULL CHECK (movement_type IN ('opening_stock','purchase','sale','adjustment_in','adjustment_out','return_in','return_out')),
    quantity INT NOT NULL,
    reference_no VARCHAR(50),
    notes TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT NOW()
);





SELECT id, 'opening_stock', current_stock, 'OPENING-2026', 'Opening stock import for Kenyan-ready demo dataset', NOW() - INTERVAL '7 days'
FROM products
WHERE current_stock > 0;

CREATE INDEX idx_products_name ON products(name);
CREATE INDEX idx_products_category_id ON products(category_id);
CREATE INDEX idx_products_supplier_id ON products(supplier_id);
CREATE INDEX idx_products_tax_id ON products(tax_id);
CREATE INDEX idx_products_sku ON products(sku);
CREATE INDEX idx_products_barcode ON products(barcode);
CREATE INDEX idx_stock_movements_product_id ON stock_movements(product_id);
CREATE INDEX idx_stock_movements_created_at ON stock_movements(created_at);

CREATE OR REPLACE VIEW vw_low_stock_products AS
SELECT
    p.id,
    p.sku,
    p.name,
    c.name AS category_name,
    tc.code AS tax_code,
    tc.tax_type,
    tc.rate AS vat_rate,
    p.current_stock,
    p.reorder_level,
    (p.reorder_level - p.current_stock) AS shortage
FROM products p
JOIN categories c ON c.id = p.category_id
JOIN tax_codes tc ON tc.id = p.tax_id
WHERE p.current_stock <= p.reorder_level
ORDER BY shortage DESC, p.name ASC;

-- Reset sequences
SELECT setval(pg_get_serial_sequence('tax_codes','id'), COALESCE((SELECT MAX(id) FROM tax_codes),1), TRUE);
SELECT setval(pg_get_serial_sequence('categories','id'), COALESCE((SELECT MAX(id) FROM categories),1), TRUE);
SELECT setval(pg_get_serial_sequence('suppliers','id'), COALESCE((SELECT MAX(id) FROM suppliers),1), TRUE);
SELECT setval(pg_get_serial_sequence('products','id'), COALESCE((SELECT MAX(id) FROM products),1), TRUE);
SELECT setval(pg_get_serial_sequence('stock_movements','id'), COALESCE((SELECT MAX(id) FROM stock_movements),1), TRUE);

COMMIT;